DROP DATABASE IF EXISTS dat_xe_ve_que;
CREATE DATABASE dat_xe_ve_que CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE dat_xe_ve_que;

CREATE TABLE users (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  phone VARCHAR(50) NOT NULL UNIQUE,
  email VARCHAR(255) NULL UNIQUE,
  password_hash VARCHAR(255) NOT NULL,
  role ENUM('ADMIN','DISPATCHER','ACCOUNTANT','DRIVER','CUSTOMER') NOT NULL,
  status ENUM('ACTIVE','LOCKED') NOT NULL DEFAULT 'ACTIVE',
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);
CREATE TABLE customers (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NULL UNIQUE, name VARCHAR(255) NOT NULL, phone VARCHAR(50) NOT NULL, zalo_phone VARCHAR(50) NULL, note TEXT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id));
CREATE TABLE drivers (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NULL UNIQUE, name VARCHAR(255) NOT NULL, phone VARCHAR(50) NOT NULL, zalo_phone VARCHAR(50), status VARCHAR(100) DEFAULT 'Rảnh', current_location VARCHAR(255), direction_preference VARCHAR(255), seats_free INT DEFAULT 0, note TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id));
CREATE TABLE vehicles (id INT AUTO_INCREMENT PRIMARY KEY, driver_id INT NOT NULL, vehicle_type VARCHAR(100) NOT NULL, seats INT NOT NULL, license_plate VARCHAR(50), status VARCHAR(100) DEFAULT 'Đang hoạt động', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (driver_id) REFERENCES drivers(id));
CREATE TABLE locations (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(255) NOT NULL, slug VARCHAR(255) UNIQUE NOT NULL, type VARCHAR(50) NOT NULL, parent_id INT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE routes (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(255) NOT NULL, slug VARCHAR(255) UNIQUE NOT NULL, from_name VARCHAR(255) NOT NULL, to_name VARCHAR(255) NOT NULL, direction VARCHAR(255) NOT NULL, distance_km DECIMAL(8,2), estimated_duration_min INT, seo_title VARCHAR(255), seo_description TEXT, content LONGTEXT, status VARCHAR(100) DEFAULT 'Đang chạy', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE services (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(255) NOT NULL, slug VARCHAR(255) UNIQUE NOT NULL, type ENUM('SHARED_RIDE','PRIVATE_RIDE','CARGO','MARKET','CONTRACT','WEDDING','TOUR','HOSPITAL','AIRPORT') UNIQUE NOT NULL, description TEXT, status VARCHAR(100) DEFAULT 'Đang bật', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE price_rules (id INT AUTO_INCREMENT PRIMARY KEY, service_type ENUM('SHARED_RIDE','PRIVATE_RIDE','CARGO','MARKET','CONTRACT','WEDDING','TOUR','HOSPITAL','AIRPORT') NOT NULL, route_id INT NULL, vehicle_type VARCHAR(100), pricing_type VARCHAR(50) NOT NULL, base_price DECIMAL(12,2) DEFAULT 0, price_per_person DECIMAL(12,2) DEFAULT 0, price_per_kg DECIMAL(12,2) DEFAULT 0, commission_type VARCHAR(50) DEFAULT 'FIXED', commission_value DECIMAL(12,2) DEFAULT 0, active BOOLEAN DEFAULT TRUE, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (route_id) REFERENCES routes(id));
CREATE TABLE bookings (id INT AUTO_INCREMENT PRIMARY KEY, code VARCHAR(50) UNIQUE NOT NULL, customer_id INT NULL, customer_name VARCHAR(255) NOT NULL, customer_phone VARCHAR(50) NOT NULL, type ENUM('SHARED_RIDE','PRIVATE_RIDE','CARGO','MARKET','CONTRACT','WEDDING','TOUR','HOSPITAL','AIRPORT') NOT NULL, route_id INT NULL, direction VARCHAR(255), pickup_address VARCHAR(500), dropoff_address VARCHAR(500), scheduled_at DATETIME NULL, passenger_count INT DEFAULT 1, vehicle_type VARCHAR(100), cargo_description TEXT, market_description TEXT, note TEXT, status ENUM('NEW','CONTACTED','QUOTED','WAITING_DEPOSIT','DEPOSITED','WAITING_DISPATCH','ASSIGNED','DRIVER_ACCEPTED','IN_PROGRESS','COMPLETED','CANCELLED','NO_SHOW') DEFAULT 'NEW', estimated_total DECIMAL(12,2) DEFAULT 0, final_total DECIMAL(12,2) DEFAULT 0, commission_amount DECIMAL(12,2) DEFAULT 0, payment_receiver VARCHAR(50) DEFAULT 'DRIVER', source VARCHAR(50) DEFAULT 'WEBSITE', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (customer_id) REFERENCES customers(id), FOREIGN KEY (route_id) REFERENCES routes(id));
CREATE TABLE trips (id INT AUTO_INCREMENT PRIMARY KEY, code VARCHAR(50) UNIQUE NOT NULL, route_id INT NOT NULL, driver_id INT NULL, vehicle_id INT NULL, departure_at DATETIME NOT NULL, total_seats INT DEFAULT 0, booked_seats INT DEFAULT 0, available_seats INT DEFAULT 0, status ENUM('COLLECTING','READY','IN_PROGRESS','COMPLETED','CANCELLED') DEFAULT 'COLLECTING', total_customer_amount DECIMAL(12,2) DEFAULT 0, admin_commission DECIMAL(12,2) DEFAULT 0, driver_net_amount DECIMAL(12,2) DEFAULT 0, driver_debt_amount DECIMAL(12,2) DEFAULT 0, settlement_status ENUM('PENDING','PARTIAL','PAID','RECONCILED','WAIVED','DISPUTED') DEFAULT 'PENDING', note TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY(route_id) REFERENCES routes(id), FOREIGN KEY(driver_id) REFERENCES drivers(id), FOREIGN KEY(vehicle_id) REFERENCES vehicles(id));
CREATE TABLE trip_bookings (id INT AUTO_INCREMENT PRIMARY KEY, trip_id INT NOT NULL, booking_id INT NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY trip_booking_unique (trip_id, booking_id), FOREIGN KEY(trip_id) REFERENCES trips(id), FOREIGN KEY(booking_id) REFERENCES bookings(id));
CREATE TABLE driver_settlement_payments (id INT AUTO_INCREMENT PRIMARY KEY, trip_id INT NULL, driver_id INT NOT NULL, amount DECIMAL(12,2) NOT NULL, direction VARCHAR(50) NOT NULL, method VARCHAR(50) NOT NULL, note TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE site_settings (id INT AUTO_INCREMENT PRIMARY KEY, `key` VARCHAR(100) UNIQUE NOT NULL, value TEXT, group_name VARCHAR(100) DEFAULT 'general', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE media_files (id INT AUTO_INCREMENT PRIMARY KEY, original_name VARCHAR(255) NOT NULL, file_name VARCHAR(255) NOT NULL, file_url VARCHAR(500) NOT NULL, mime_type VARCHAR(100) NOT NULL, size_bytes INT NOT NULL, alt_text VARCHAR(255) NOT NULL, title VARCHAR(255), usage_type VARCHAR(100) NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE post_categories (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(255) NOT NULL, slug VARCHAR(255) UNIQUE NOT NULL);
CREATE TABLE posts (id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(255) NOT NULL, slug VARCHAR(255) UNIQUE NOT NULL, excerpt TEXT, content LONGTEXT NOT NULL, category_id INT NULL, status VARCHAR(50) DEFAULT 'DRAFT', published_at DATETIME NULL, seo_title VARCHAR(255), seo_description TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY(category_id) REFERENCES post_categories(id));

